import { Component, OnInit } from '@angular/core';
import { MatDialog } from '@angular/material/dialog';
import { MAT_DIALOG_DATA } from '@angular/material/dialog';
import { Inject } from '@angular/core';

@Component({
	selector: 'app-content',
	templateUrl: './content.component.html',
	styleUrls: ['./content.component.css']
})
export class ContentComponent implements OnInit {

	public projects = [
		{
			title: "Space Shooter",
			imgPaths: ["assets/space 3.png", "assets/space 1.png"],
			stack: ["Python", "Pygame", "Sprites"],
			class: "fade-right",
			curImgIdx: 0,
			id: "img1"
		},
		{
			title: "Movie Nomination",
			imgPaths: ["assets/movFinder 1.png", "assets/movFinder 2.png"],
			stack: ["Angular", "Typescript", "HTML", "CSS", "Angular Material", "OMDB API"],
			class: "fade-right",
			curImgIdx: 0,
			id: "img2"
		},
		{
			title: "Vehicle Registration",
			imgPaths: ["assets/car 2.png", "assets/car 1.png", "assets/car 3.png"],
			stack: ["Java", "OOP", "Polymorphism"],
			class: "fade-right",
			curImgIdx: 0,
			id: "img3"
		},
		{
			title: "Connect Four",
			imgPaths: ["assets/connect4 1.png", "assets/connect4 2.png", "assets/connect4 3.png"],
			stack: ["Java", "OOP", "Android Studio"],
			class: "fade-right",
			curImgIdx: 0,
			id: "img4"
		}
	]

	public selectedImg;

	public breakpoint;

	constructor(public dialog: MatDialog) { }

	ngOnInit(): void {
		this.breakpoint = this.checkBreakpoints(window);

		// List of sentences
		var _CONTENT = [
			"Software Engineer",
			"Mobile Developer",
			"University Student",
			"Full-Stack Developer"
		];

		// Current sentence being processed
		var _PART = 0;

		// Character number of the current sentence being processed 
		var _PART_INDEX = 0;

		// Holds the handle returned from setInterval
		var _INTERVAL_VAL;

		// Element that holds the text
		var _ELEMENT = document.querySelector("#text");

		// Cursor element 
		var _CURSOR = <any>document.querySelector("#cursor");

		// Implements typing effect
		function Type() {
			// Get substring with 1 characater added
			var text = _CONTENT[_PART].substring(0, _PART_INDEX + 1);
			_ELEMENT.innerHTML = text;
			_PART_INDEX++;

			// If full sentence has been displayed then start to delete the sentence after some time
			if (text === _CONTENT[_PART]) {
				// Hide the cursor
				_CURSOR.style.display = 'none';

				clearInterval(_INTERVAL_VAL);
				setTimeout(function () {
					_INTERVAL_VAL = setInterval(Delete, 50);
				}, 2000);
			}
		}

		// Implements deleting effect
		function Delete() {
			// Get substring with 1 characater deleted
			var text = _CONTENT[_PART].substring(0, _PART_INDEX - 1);
			_ELEMENT.innerHTML = text;
			_PART_INDEX--;

			// If sentence has been deleted then start to display the next sentence
			if (text === '') {
				clearInterval(_INTERVAL_VAL);

				// If current sentence was last then display the first one, else move to the next
				if (_PART == (_CONTENT.length - 1))
					_PART = 0;
				else
					_PART++;

				_PART_INDEX = 0;

				// Start to display the next sentence after some time
				setTimeout(function () {
					_CURSOR.style.display = 'inline-block';
					_INTERVAL_VAL = setInterval(Type, 100);
				}, 200);
			}
		}

		// Start the typing effect on load
		_INTERVAL_VAL = setInterval(Type, 100);
	}

	openDialog(project) {
		this.dialog.open(ProjectDlgComponent, {
			data: { project }
		});
	}

	closeDlg() {
		this.dialog.closeAll();
	}

	changeImgClicked(id) {
		var element = document.getElementById(id);
		element.classList.remove("fade");
		setTimeout(function () { element.classList.add("fade"); }, 10);

	}

	onResize(event: any) {
		this.breakpoint = this.checkBreakpoints(event.target);
	}

	//Determine breakpoints for nominations grid list 
	checkBreakpoints(target: any) {
		if (target.innerWidth <= 1000) {
			return 1;
		}
		if (target.innerWidth <= 1400) {
			return 2;
		}
		return 3;
	}



}




